function tr(key){
  const base = C[key];
  const o = (TR[LANG] && TR[LANG].cards && TR[LANG].cards[key]) || {};
  return Object.assign({}, base, {
    tag:   o.tag   || base.tag,
    title: o.title || base.title,
    date:  o.date  || base.date,
    sum:   o.sum   || base.sum,
    bullets: base.bullets.map((b,i)=> (o.bullets && o.bullets[i]) || b),
    stats:   base.stats.map((s,i)=> (o.stats && o.stats[i]) || s),
  });
}
function t(k){ return (TR[LANG] && TR[LANG]._ui && TR[LANG]._ui[k]) || UI_EN[k]; }

function applyLang(lang){
  LANG = LANGS[lang] ? lang : 'es';
  try { localStorage.setItem('dais.lang', LANG); } catch(e){}
  document.documentElement.lang = LANG;
  document.documentElement.dir = RTL[LANG] ? 'rtl' : 'ltr';
  const sel = document.getElementById('langSel');
  if(sel) sel.value = LANG;
  if(typeof route === 'function') route();
}
